/**
 * n8n Code node — PROCESAR DATOS
 * ---------------------------------------------------------
 * OBJETIVO
 *  - Tomar los retiros filtrados (no avisados) desde "FiltroRetiros".
 *  - Cruzar esos materiales contra el stock (FiltroStock → fallback ControlStock).
 *  - Agrupar por material, sumar cantidades, redondear a enteros.
 *  - Añadir `source_rows` con los rowNumber de retiros (para update después).
 *
 * NOTAS:
 *  - Se eliminó $input.all(): ahora el origen de datos es fijo → los retiros SIEMPRE
 *    se leen desde el nodo "FiltroRetiros".
 *  - Esto garantiza que no se cuelen 1890 filas de stock como antes.
 */

/* ──────────────────────────────────────────── */
/* 0) Nombres de nodos (ajustar si cambian)     */
/* ──────────────────────────────────────────── */
const NODE_RETIROS = 'FiltroRetiros';
const NODE_STOCK   = 'FiltroStock';      // fallback: 'ControlStock'

/* ──────────────────────────────────────────── */
/* 1) Helpers                                   */
/* ──────────────────────────────────────────── */
function norm(s) {
  if (s == null) return '';
  return String(s)
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}
function num(v) {
  if (v == null || v === '') return 0;
  if (typeof v === 'number') return v;
  const n = Number(String(v).replace(',', '.'));
  return isNaN(n) ? 0 : n;
}
function pickField(obj, candidates) {
  for (const c of candidates) {
    if (Object.prototype.hasOwnProperty.call(obj, c)) return c;
    const k = Object.keys(obj).find(k => norm(k) === norm(c));
    if (k) return k;
  }
  return null;
}
function safeItems(node) {
  try { return $items(node, 0, 0) || []; }
  catch { return []; }
}

/* ──────────────────────────────────────────── */
/* 2) Entradas                                  */
/* ──────────────────────────────────────────── */
const retirosItems = safeItems(NODE_RETIROS);
let stockItems     = safeItems(NODE_STOCK);
if (!stockItems.length) stockItems = safeItems('ControlStock');

if (!retirosItems.length) {
  return [{ warning: 'No llegaron retiros desde FiltroRetiros' }];
}
if (!stockItems.length) {
  return [{ warning: 'No llegaron datos de stock (FiltroStock ni ControlStock)' }];
}

/* ──────────────────────────────────────────── */
/* 3) Descubrir columnas                        */
/* ──────────────────────────────────────────── */
const sampleRet   = retirosItems[0].json || {};
const sampleStock = stockItems[0].json   || {};

const COL_MATERIAL_RETIROS = pickField(sampleRet, ['MATERILAES','MATERIALES','MATERIAL','Material','material']);
const COL_CANTIDAD         = pickField(sampleRet, ['CANTIDAD','Cantidad','cantidad','QTY','Qty','qty']);
const COL_ROWNUMBER        = pickField(sampleRet, ['rowNumber','RowNumber','row_number','__row__']);

if (!COL_MATERIAL_RETIROS || !COL_CANTIDAD) {
  return [{ error: 'Faltan columnas en RETIROS', sampleRet }];
}
const COL_MATERIAL_STOCK = pickField(sampleStock, ['MATERIAL','Material','material']);
const COL_FISICO         = pickField(sampleStock, ['FISICO','Stock Fisico','stock fisico','E']);
const COL_VIRTUAL        = pickField(sampleStock, ['VIRTUAL','Stock Virtual','stock virtual','F']);

/* ──────────────────────────────────────────── */
/* 4) Agrupar retiros                           */
/* ──────────────────────────────────────────── */
const retirosMap = new Map();

for (const it of retirosItems) {
  const row     = it.json || {};
  const rawName = row[COL_MATERIAL_RETIROS];
  const qty     = num(row[COL_CANTIDAD]);
  if (!rawName || !qty) continue;

  const key = norm(rawName);
  const current = retirosMap.get(key) || {
    material_display: String(rawName).trim(),
    retiro_total: 0,
    source_rows: []
  };

  current.retiro_total += qty;
  const rn = COL_ROWNUMBER ? Number(row[COL_ROWNUMBER]) : undefined;
  if (Number.isFinite(rn)) current.source_rows.push(rn);

  retirosMap.set(key, current);
}

/* ──────────────────────────────────────────── */
/* 5) Indexar stock                             */
/* ──────────────────────────────────────────── */
const stockMap = new Map();
for (const it of stockItems) {
  const row = it.json || {};
  const rawName = row[COL_MATERIAL_STOCK];
  if (!rawName) continue;
  const key = norm(rawName);
  stockMap.set(key, {
    fisico:  COL_FISICO  ? num(row[COL_FISICO])  : null,
    virtual: COL_VIRTUAL ? num(row[COL_VIRTUAL]) : null
  });
}

/* ──────────────────────────────────────────── */
/* 6) Cruce y salida                            */
/* ──────────────────────────────────────────── */
const out = [];
for (const [key, agg] of retirosMap.entries()) {
  const hit = stockMap.get(key);
  out.push({
    MATERIAL: agg.material_display,
    RETIRO_TOTAL: Math.round(agg.retiro_total),
    STOCK_FISICO: hit ? Math.round(hit.fisico)   : null,
    STOCK_VIRTUAL: hit ? Math.round(hit.virtual) : null,
    EN_STOCK: !!hit,
    source_rows: agg.source_rows
  });
}
out.sort((a,b)=>norm(a.MATERIAL).localeCompare(norm(b.MATERIAL)));

return out.map(o => ({ json: o }));

// 1) Intentamos obtener variables de entorno con un bloque de seguridad
let destTo = "5492262587575@s.whatsapp.net";
let pageSize = 15;

try {
  // Intentamos leer del entorno, si falla usamos los valores por defecto definidos arriba
  destTo = $env.EVOLUTION_TO || destTo;
  pageSize = Number($env.PAGE_SIZE || pageSize);
} catch (e) {
  // Si n8n bloquea el acceso, el código seguirá usando los valores por defecto sin dar error
  console.log("Acceso a variables de entorno denegado, usando valores por defecto.");
}

// 2) Tomamos todos los items del nodo anterior
const items = $input.all().map(i => i.json);

// 3) Helper para formatear cada línea
function lineOf(row) {
  const mat = String(row.MATERIAL || "").trim();
  const ret = Math.round(Number(row.RETIRO_TOTAL || 0));
  const fis = row.STOCK_FISICO == null ? "—" : Math.round(Number(row.STOCK_FISICO));
  const vir = row.STOCK_VIRTUAL == null ? "—" : Math.round(Number(row.STOCK_VIRTUAL));

  return `• *${mat}*\n    Retiro: *${ret}* | Físico: *${fis}* | Virtual: *${vir}*`;
}

const allLines = items.map(lineOf);

// 4) Paginamos
const pages = [];
for (let i = 0; i < allLines.length; i += pageSize) {
  const slice = allLines.slice(i, i + pageSize);
  pages.push(slice);
}

// 5) Armamos salida
const total = pages.length || 1;
const now = new Date();
const fecha = now.toLocaleDateString('es-AR');
const hora = now.toLocaleTimeString('es-AR', { hour: '2-digit', minute: '2-digit' });

// Si no hay items, devolvemos al menos un objeto vacío para no romper el flujo
if (pages.length === 0) {
    return [{ json: { to: destTo, message: "No hay datos para mostrar." } }];
}

return pages.map((lines, idx) => {
  return {
    json: {
      to: destTo,
      page_index: idx + 1,
      page_count: total,
      header: `*Retiros vs Stock* — ${fecha} ${hora} (pág. ${idx + 1}/${total})`,
      lines
    }
  };
});

/**
 * n8n Code node — Recolectar rowNumber únicos para marcar "ya avisado"
 * Debe existir en el nodo "ProcesarDatos" un campo `source_rows: number[]` por ítem.
 * Este code:
 *  - Junta todos los rowNumber
 *  - Los desduplica
 *  - Emite 1 item por fila con los valores a escribir en la hoja
 */

const SOURCE_NODE = 'ProcesarDatos';     // <-- AJUSTÁ si tu nodo se llama distinto
const COL_ALERTA  = 'ALERTA_ENVIO';      // <-- nombre de columna a escribir
const COL_TS      = 'ALERTA_TS';         // <-- otra columna (timestamp)

const all = $items(SOURCE_NODE, 0, 0) || [];

const set = new Set();
for (const it of all) {
  const rows = (it.json && it.json.source_rows) || [];
  for (const rn of rows) {
    if (rn != null) set.add(Number(rn));
  }
}

// Si no encontró nada, devolvemos un aviso (no error)
if (set.size === 0) {
  return [{
    json: {
      info: 'No se hallaron rowNumber para marcar. Verificá que ProcesarDatos emita source_rows[].'
    }
  }];
}

// Timestamp legible
const now = new Date();
const ts  = now.toISOString(); // o toLocaleString('es-AR')

// Emitimos 1 item por fila a actualizar
return Array.from(set).map(rowNumber => ({
  json: {
    rowNumber,
    [COL_ALERTA]: 'SI',
    [COL_TS]: ts
  }
}));

/**
 * n8n Code node — Construir body de WhatsApp por página
 */

// 1) Obtener límite de caracteres con fallback de seguridad
let maxChars = 3500;
try {
  maxChars = Number($env.WHATSAPP_MAX_CHARS || 3500);
} catch (e) {
  // Si falla el acceso a env, usamos el valor por defecto
  maxChars = 3500;
}

function buildBody({ header, lines }, limit) {
  // Encabezado + líneas separadas
  const text = `${header}\n\n${lines.join('\n\n')}`;
  if (text.length <= limit) return text;

  // Si se excede, recortamos líneas manteniendo el encabezado
  const out = [header, ""];
  let acc = header.length + 2;

  for (const ln of lines) {
    const plus = ln.length + 2; // +2 por los saltos de línea \n\n
    if (acc + plus > limit - 40) { // Margen para el aviso de truncado
      out.push("\n_(Contenido truncado por longitud)_");
      break;
    }
    out.push(ln);
    out.push(""); // Espacio entre items
    acc += plus;
  }
  return out.join('\n').trim();
}

const results = [];

// 2) Procesar cada item que viene del nodo de paginación
for (const item of $input.all()) {
  const data = item.json;
  const { to, header, lines, page_index, page_count } = data;

  if (!to) {
    results.push({
      json: {
        error: true,
        reason: "Falta 'to' (destinatario). Revisa las variables de entorno o el nodo anterior.",
        originalData: data
      }
    });
    continue;
  }

  // Si lines no es un array (por seguridad), lo manejamos
  const safeLines = Array.isArray(lines) ? lines : [];
  const body = buildBody({ header, lines: safeLines }, maxChars);

  results.push({
    json: {
      number: to, // Renombrado a 'number' si es lo que pide Evolution API, o mantén 'to'
      body,
      page_metadata: {
        current: page_index,
        total: page_count
      }
    }
  });
}

return results;
